import json
import re

# Step 1: Get latest NPM packages with their versions
file_path = locals()['var_functions.query_db:36']
with open(file_path, 'r') as f:
    npm_releases = json.load(f)

# Parse VersionInfo to extract Ordinal
for pkg in npm_releases:
    version_info_str = pkg['VersionInfo']
    ordinal_match = re.search(r'"Ordinal":\s*(\d+)', version_info_str)
    pkg['Ordinal'] = int(ordinal_match.group(1)) if ordinal_match else 0

# Group by package name and find latest version (highest Ordinal)
latest_packages = {}
for pkg in npm_releases:
    name = pkg['Name']
    if name not in latest_packages or pkg['Ordinal'] > latest_packages[name]['Ordinal']:
        latest_packages[name] = {
            'Name': name,
            'Version': pkg['Version'],
            'Ordinal': pkg['Ordinal']
        }

latest_packages_dict = {pkg['Name']: pkg for pkg in latest_packages.values()}

print('__RESULT__:')
print(json.dumps({
    'total_latest_packages': len(latest_packages_dict),
    'sample_keys': list(latest_packages_dict.keys())[:5]
}))

